:**boot_treat_pl_rx04**;

if ( Message GO ? \n bl_pl_data0_b2 = 'G' ?) then (oui)
    :**boot_wakeup**;
    if ( Message GO suite ? \n bl_pl_data1_b2 = 'O' ?) then (oui)
    else (non)
        :**boot_ERREUR_Inconnue**;
        detach
    endif

    detach
elseif ( Message RS ? \n bl_pl_data0_b2 = 'R' ?) then (oui)
