    :boot_Ready;
    detach
elseif ( Message WF ecriture Flash ? \n bl_pl_data0_b2 = 'W' ?) then (oui)
    :boot_FlashWr_data;
    detach
elseif ( Message EE ecriture EEPROM ? \n bl_pl_data0_b2 = 'E' ?) then (oui)
