    detach
elseif ( Message demande version ? \n bl_pl_data0_b2 = 'F' ?) then (oui)
    :envoi de la version dans l'ack \n blackversion = 1;
    :Envoi ACK ();
    detach
elseif ( Message demande UID ? \n bl_pl_data0_b2 = 'U' ?) then (oui)
